/**
  * @file   Delay.c
  * @brief  软件延时
  * @author SleetGit
  * @date   2026/4/29.
  */

#include "mcs51/8052.h"

void Delay(unsigned int xms)
{
	unsigned char i, j;
	while(xms--)
	{
		i = 2;
		j = 239;
		do
		{
			while (--j);
		} while (--i);
	}
}

#include "mcs51/8052.h"

/* Delay.c
 * 软件阻塞延时实现。
 * Delay(xms)：阻塞近似 xms 毫秒（与编译器与晶振频率相关）。
 */

void Delay(unsigned int xms)
{
	unsigned char i, j;
	while(xms--)
	{
		i = 2;
		j = 239;
		do
		{
			while (--j);
		} while (--i);
	}
}

#ifndef __LCD1602_H__ #define __LCD1602_H__
//用户调用函数： void LCD_Init(void);//初始化 void LCD_Clear(void);//清屏 void LCD_SetCursor(unsigned char Line,unsigned char Column);//显示光标 void LCD_ShowChar(unsigned char Line,unsigned char Column,char Char);//显示一个字符 void LCD_ShowString(unsigned char Line,unsigned char Column,char *String);//显示一个字符串 void LCD_ShowNum(unsigned char Line,unsigned char Column,unsigned int Number,unsigned char Length);//显示十进制数字 void LCD_ShowSignedNum(unsigned char Line,unsigned char Column,int Number,unsigned char Length);//显示有符号十进制数字 void LCD_ShowHexNum(unsigned char Line,unsigned char Column,unsigned int Number,unsigned char Length);//显示十六进制数字 void LCD_ShowBinNum(unsigned char Line,unsigned char Column,unsigned int Number,unsigned char Length);//显示二进制数字
#endif

/* LCD1602.h * LCD1602 显示驱动接口（8-bit 并口模式）。 * 提供初始化、清屏、设置光标与各种格式的显示函数。 */
#ifndef __LCD1602_H__ #define __LCD1602_H__
/* 用户接口 */ void LCD_Init(void); /* 初始化 LCD */ void LCD_Clear(void); /* 清屏 */ void LCD_SetCursor(unsigned char Line,unsigned char Column); /* 设置光标位置：Line=1~2, Column=1~16 */ void LCD_ShowChar(unsigned char Line,unsigned char Column,char Char); /* 在指定位置显示单字符 */ void LCD_ShowString(unsigned char Line,unsigned char Column,char *String); /* 在指定位置显示字符串 */ void LCD_ShowNum(unsigned char Line,unsigned char Column,unsigned int Number,unsigned char Length); /* 显示无符号十进制数 */ void LCD_ShowSignedNum(unsigned char Line,unsigned char Column,int Number,unsigned char Length); /* 显示有符号十进制数 */ void LCD_ShowHexNum(unsigned char Line,unsigned char Column,unsigned int Number,unsigned char Length); /* 显示十六进制数 */ void LCD_ShowBinNum(unsigned char Line,unsigned char Column,unsigned int Number,unsigned char Length); /* 显示二进制数 */
#endif

/* MatrixKey.h * 按键读取接口。 * GetKey() 返回按键编号：0 表示无键，1..n 表示对应按键。 */
#ifndef __MATRIXKEY_H__ #define __MATRIXKEY_H__
unsigned char GetKey(void);
#endif
